    xQueueSend(xQueue, &c, portMAX_DELAY); // Still blocks
}

void vProcessingTask(void *pvParameters)
{
    char rx_char;
    for(;;)
    {
        if(xQueueReceive(xQueue, &rx_char, 100) == pdPASS)
        {
        }
        vTaskDelay(10);
    }
}

int main(void)
{
    // Queue depth increased to 64
    xQueue = xQueueCreate(64, sizeof(char));
    NVIC_EnableIRQ(UART0_IRQn);
    xTaskCreate(vProcessingTask, "Processor", 100, NULL, 1, NULL);
    vTaskStartScheduler();
    for(;;);
}
